final:
module full_adder (
    input a,
    input b,
    input cin,
    output sum,
    output cout
);

    wire fa_s1, c1, c2;

    half_adder ha1 (.a(a), .b(b), .sum(fa_s1), .cout(c1));
    half_adder ha2 (.a(fa_s1), .b(cin), .sum(sum), .cout(c2));

    assign cout = c1 | c2;

endmodule

module half_adder (
    input a,
    input b,
    output sum,
    output cout
);

    assign sum = a ^ b;
    assign cout = a & b;

endmodule
